const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const secret = body.internal_secret || '';
if (!secret || secret !== (process.env.INTERNAL_EMAIL_SECRET || '')) return { json: { _unauthorized: true, error: 'internal secret required' } };
if (!body.lead_id || !body.signal_type) return { json: { _empty: true, error: 'lead_id and signal_type required' } };
// Map BI signal_type → review trigger metadata.
const map = {
  baby_born: { trigger: 'baby', priority: 'high' },
  marriage: { trigger: 'marriage', priority: 'high' },
  job_change: { trigger: 'new_job', priority: 'high' },
  job_loss: { trigger: 'job_loss', priority: 'urgent' },
  home_purchase: { trigger: 'home_purchase', priority: 'high' },
  business_expansion: { trigger: 'business_expansion', priority: 'high' },
  birthday_window_7d: { trigger: 'birthday', priority: 'medium' },
  birthday: { trigger: 'birthday', priority: 'medium' },
  retirement_planning_age: { trigger: 'retirement_planning_age', priority: 'high' },
  child_milestone: { trigger: 'child_milestone', priority: 'medium' }
};
const spec = map[body.signal_type] || { trigger: body.signal_type, priority: 'medium' };
// Birthday is annual touchpoint, others are triggered_event reviews.
const reviewType = (spec.trigger === 'birthday') ? 'annual' : 'triggered_event';
return { json: { _authorized: true, lead_id: body.lead_id, signal_id: body.signal_id || null, signal_type: body.signal_type, trigger_signal_type: spec.trigger, review_type: reviewType, priority: spec.priority, signal_data: body.signal_data || {} } };

const ctx = $('Validate + Map Signal').item.json;
const rows = $input.item.json;
const lead = (Array.isArray(rows) ? rows[0] : rows) || null;
if (!lead || !lead.id) return { json: { _no_lead: true, error: 'lead not found' } };
return { json: { lead: lead, ctx: ctx } };

const carry = $('Carry Lead').item.json;
const rows = $input.item.json;
const pol = (Array.isArray(rows) ? rows[0] : rows) || null;
if (!pol || !pol.id) return { json: { _no_policy: true, error: 'no in-force policy for client — skipping triggered review (signal will still be processed by BI pipeline)' } };
return { json: {
  insert_row: {
    vertical_id: 'insurance',
    policy_application_id: pol.id,
    client_id: carry.lead.client_id,
    lead_id: carry.lead.id,
    advisor_id: pol.advisor_id || carry.lead.assigned_advisor_id,
    review_type: carry.ctx.review_type,
    trigger_source: 'behavioral_signal',
    trigger_signal_id: carry.ctx.signal_id,
    trigger_signal_type: carry.ctx.trigger_signal_type,
    scheduled_date: new Date().toISOString().slice(0,10),
    due_date: new Date(Date.now() + 7*86400000).toISOString().slice(0,10),
    priority: carry.ctx.priority,
    status: 'scheduled',
    video_engagement_status: 'not_sent'
  },
  advisor_id: pol.advisor_id || carry.lead.assigned_advisor_id,
  client_id: carry.lead.client_id,
  lead_id: carry.lead.id,
  policy_application_id: pol.id
} };
